/**
 * @summary Admin - list all shops with status
 */
export const getAdminListShopsUrl = (params?: AdminListShopsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/shops?${stringifiedParams}`
    : `/api/admin/shops`;
};

export const adminListShops = async (
  params?: AdminListShopsParams,
  options?: RequestInit,
): Promise<ShopListResponse> => {
  return customFetch<ShopListResponse>(getAdminListShopsUrl(params), {
    ...options,
    method: "GET",
  });
};

